sql:
SELECT offense_rating, offense_efficiency
FROM offensive_ratings
WHERE team_id = 1;

SELECT net_rating 
FROM net_ratings 
WHERE game_id = 1 AND team_id = 1;

SELECT COUNT(*) 
FROM conferences
WHERE conference_name = 'Eastern Conference';

SELECT MAX(pts) AS max_points
FROM player_stats
WHERE game_id = (
    SELECT game_id
    FROM games
    WHERE attendance = (
        SELECT MAX(attendance)
        FROM games
    )
);
